interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

interface ParseError {
  row: number;
  message: string;
}

type CoercedValue = string | number | boolean | null;

interface CSVRow {
  [key: string]: CoercedValue;
}

interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: ParseError[];
  filter: (predicate: (row: CSVRow) => boolean) => CSVRow[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<CoercedValue, CSVRow[]>;
}

// Type coercion function
function coerceValue(value: string): CoercedValue {
  // Check for null values
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Check for booleans (case insensitive)
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for numbers
  const trimmed = value.trim();
  if (trimmed !== '' && !isNaN(Number(trimmed))) {
    return Number(trimmed);
  }

  // Return as string
  return value;
}

// Parse a single CSV line handling quotes, escaped quotes, and delimiters
function parseCSVLine(
  line: string,
  delimiter: string,
  quoteChar: string
): string[] {
  const fields: string[] = [];
  let currentField = '';
  let insideQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === quoteChar) {
      // Check if it's an escaped quote (two quotes in a row)
      if (i + 1 < line.length && line[i + 1] === quoteChar) {
        currentField += quoteChar;
        i++; // Skip the next quote
      } else {
        // Toggle inside quotes state
        insideQuotes = !insideQuotes;
      }
    } else if (char === delimiter && !insideQuotes) {
      // End of field
      fields.push(currentField);
      currentField = '';
    } else {
      currentField += char;
    }
  }

  // Add the last field
  fields.push(currentField);

  // Check if we ended while inside quotes
  if (insideQuotes) {
    throw new Error('Unclosed quote in CSV line');
  }

  return fields;
}

// CSV parsing function
function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter || ',';
  const quoteChar = options.quoteChar || '"';
  const lineSeparator = options.lineSeparator || '\n';

  const errors: ParseError[] = [];
  const rows: CSVRow[] = [];
  let headers: string[] = [];

  // Handle empty input
  if (!input || input.trim() === '') {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: (predicate) => [],
      sum: (column) => 0,
      average: (column) => 0,
      count: () => 0,
      groupBy: (column) => new Map(),
    };
  }

  // Split by line separator
  const lines = input.split(lineSeparator);

  // Parse each line
  const parsedLines: string[][] = [];
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (line === '') continue; // Skip empty lines

    try {
      const parsedLine = parseCSVLine(line, delimiter, quoteChar);
      parsedLines.push(parsedLine);
    } catch (e) {
      errors.push({
        row: i + 1,
        message: e instanceof Error ? e.message : String(e),
      });
    }
  }

  // First line is headers
  if (parsedLines.length > 0) {
    headers = parsedLines[0];
  }

  // Parse rows (starting from index 1 since 0 is headers)
  for (let i = 1; i < parsedLines.length; i++) {
    const line = parsedLines[i];

    // Check field count matches headers
    if (line.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Expected ${headers.length} fields, got ${line.length}`,
      });
      continue;
    }

    const row: CSVRow = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerceValue(line[j]);
    }

    rows.push(row);
  }

  // Methods
  const filter = (predicate: (row: CSVRow) => boolean): CSVRow[] => {
    return rows.filter(predicate);
  };

  const sum = (column: string): number => {
    let total = 0;
    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number') {
        total += value;
      }
    }
    return total;
  };

  const average = (column: string): number => {
    let total = 0;
    let count = 0;
    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number') {
        total += value;
        count++;
      }
    }
    return count > 0 ? total / count : 0;
  };

  const count = (): number => {
    return rows.length;
  };

  const groupBy = (column: string): Map<CoercedValue, CSVRow[]> => {
    const groups = new Map<CoercedValue, CSVRow[]>();
    for (const row of rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }
    return groups;
  };

  return {
    rows,
    headers,
    errors,
    filter,
    sum,
    average,
    count,
    groupBy,
  };
}

export { parseCSV, CSVResult, CSVOptions, ParseError };

import { parseCSV } from './csv-parser';

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEqual(actual: any, expected: any, message: string) {
  if (actual !== expected) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${expected}\nActual: ${actual}`
    );
  }
}

function assertDeepEqual(actual: any, expected: any, message: string) {
  const actualStr = JSON.stringify(actual);
  const expectedStr = JSON.stringify(expected);
  if (actualStr !== expectedStr) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${expectedStr}\nActual: ${actualStr}`
    );
  }
}

function assertArrayEqual(actual: any[], expected: any[], message: string) {
  if (actual.length !== expected.length) {
    throw new Error(
      `Assertion failed: ${message}\nExpected length: ${expected.length}\nActual length: ${actual.length}`
    );
  }
  for (let i = 0; i < actual.length; i++) {
    if (actual[i] !== expected[i]) {
      throw new Error(
        `Assertion failed: ${message}\nAt index ${i}: expected ${expected[i]}, got ${actual[i]}`
      );
    }
  }
}

