assertEqual(result1.rows[0]['age'], 30, 'First row age should be 30 (coerced to number)');
assertEqual(result1.rows[1]['name'], 'Jane', 'Second row name should be Jane');
assertEqual(result1.rows[1]['city'], 'Los Angeles', 'Second row city should be Los Angeles');
console.log('вњ“ Passed\n');

